/*
输入n和k
对dp赋初始值
状压DP
输出结果 
*/
#include <bits/stdc++.h>
#define int long long
using namespace std;
int ans, n, k; 
int g[(1 << 10) + 100];
int h[(1 << 10) + 100]; 
int cnt[(1 << 10) + 100];
int dp[121][(1 << 10) + 100][121];
signed main() {
	cin >> n >> k;
	int tt = 1 << n;
	for (int i = 0; i < tt; i++) {
		g[i] = ((i & (i << 1)) == 0) && ((i & (i >> 1)) == 0);
		h[i] = i | (i << 1) | (i >> 1);
		cnt[i] = cnt[i >> 1] + (i & 1);
	}
	dp[0][0][0] = 1;
	for (int i = 0; i < n; i++) {
		for (int j = 0; j < tt; j++) {
			for (int l = 0; l <= k; l++) {
				if (dp[i][j][l]) {
					for (int p = 0; p < tt; p++) {
						if (g[p] && ((h[p] & j) == 0)) {
							dp[i + 1][p][l + cnt[p]] += dp[i][j][l];
						}
					}
				}
			}
		}
	}
	for (int i = 0; i < tt; i++) {
		ans += dp[n][i][k];
	}
	cout << ans;
}
